            }, { passive: true });

            panel.addEventListener('touchend', function (e) {
                var delta = e.changedTouches[0].clientX - swipeStartX;
                if (Math.abs(delta) < 50) return;
                Tabs.swipe(delta < 0 ? 1 : -1);
