                            rate: self._ttsRate,
                            onstart: function () { clearTimeout(_rvTimeout); },
                            onend: function () { clearTimeout(_rvTimeout); _safeEnd(); },
                            onerror: function () {
                                clearTimeout(_rvTimeout);
                                self._webSpeechFallback = true;
