                clearInterval(timer);
                return;
            }
            var subtitlesBtn = document.querySelector('.vpw-controls-subtitles');
            if (!subtitlesBtn) return;
            clearInterval(timer);
            var controls = document.querySelector('.vpw-controls');
            if (controls && !controls.classList.contains('vpw-subtitles')) {
